diff --git a/internal/tar/tar.go b/internal/tar/tar.go
--- a/internal/tar/tar.go
+++ b/internal/tar/tar.go
@@
-func dataBlocks(size int) int {
-	return size / blockSize
-}
+func dataBlocks(size int) int {
+	// Compute how many whole blocks are needed to cover every byte.
+	// Round up: if any partial block remains, reserve one more.
+	blocks := size / blockSize
+	if size%blockSize != 0 {
+		blocks = blocks + 1
+	}
+	return blocks
+}
